mapper.select:
SELECT d.*, c.category_name
FROM dish d LEFT JOIN category c ON d.category_id = c.category_id
WHERE d.dish_id = #{dishId}

mapper.update:
UPDATE dish
dish_name = #{dishName}, price = #{price}, stock = #{stock}, image = #{image}, description = #{description}, category_id = #{categoryId}, available = #{available},
WHERE dish_id = #{dishId}
